import{_ as e,o as l,c as n,a2 as s}from"./chunks/framework.CWNAqwu3.js";const u=JSON.parse('{"title":"流程设计器 — 使用指南","description":"","frontmatter":{},"headers":[],"relativePath":"workflow/designer-guide.md","filePath":"workflow/designer-guide.md"}'),i={name:"workflow/designer-guide.md"};function t(o,a,r,d,c,p){return l(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="流程设计器-—-使用指南" tabindex="-1">流程设计器 — 使用指南 <a class="header-anchor" href="#流程设计器-—-使用指南" aria-label="Permalink to &quot;流程设计器 — 使用指南&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>流程设计器是 Zen Platform 工作流引擎的可视化编辑工具，基于 AntV X6 图引擎构建。用户可以通过 拖拽节点、连线和配置属性来设计业务流程，无需编写代码。</p><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><ul><li><strong>新建流程</strong>: 导航至 <code>/admin/workflow/definitions/new</code></li><li><strong>编辑流程</strong>: 在流程列表页点击某个流程的&quot;设计&quot;按钮，跳转至 <code>/admin/workflow/definitions/:id/designer</code></li></ul><h2 id="界面布局" tabindex="-1">界面布局 <a class="header-anchor" href="#界面布局" aria-label="Permalink to &quot;界面布局&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  [保存] [预览] [撤销] [重做]              流程名称: xxx   │</span></span>
<span class="line"><span>├────────┬─────────────────────────────────┬───────────────┤</span></span>
<span class="line"><span>│        │                                 │               │</span></span>
<span class="line"><span>│  节点   │         X6 画布区域              │   属性面板    │</span></span>
<span class="line"><span>│  面板   │                                 │               │</span></span>
<span class="line"><span>│        │    ┌─────┐    ┌─────┐           │  节点名称:    │</span></span>
<span class="line"><span>│ ○ 开始  │    │节点A│───→│节点B│           │  候选用户:    │</span></span>
<span class="line"><span>│ ◻ 用户  │    └─────┘    └─────┘           │  候选角色:    │</span></span>
<span class="line"><span>│ ◇ 审批  │                                 │  截止时间:    │</span></span>
<span class="line"><span>│ ◆ 排他  │                                 │  条件表达式:  │</span></span>
<span class="line"><span>│ ◈ 并行  │                                 │               │</span></span>
<span class="line"><span>│ ○ 结束  │                                 │               │</span></span>
<span class="line"><span>│        │                                 │               │</span></span>
<span class="line"><span>└────────┴─────────────────────────────────┴───────────────┘</span></span></code></pre></div><h2 id="节点类型" tabindex="-1">节点类型 <a class="header-anchor" href="#节点类型" aria-label="Permalink to &quot;节点类型&quot;">​</a></h2><h3 id="_1-开始事件-start-event" tabindex="-1">1. 开始事件 (Start Event) <a class="header-anchor" href="#_1-开始事件-start-event" aria-label="Permalink to &quot;1. 开始事件 (Start Event)&quot;">​</a></h3><ul><li><strong>图标</strong>: 绿色圆圈</li><li><strong>作用</strong>: 流程的入口点，每个流程必须有且只有一个开始事件</li><li><strong>属性</strong>: 无特殊配置</li><li><strong>规则</strong>: 只能有出边，不能有入边</li></ul><h3 id="_2-结束事件-end-event" tabindex="-1">2. 结束事件 (End Event) <a class="header-anchor" href="#_2-结束事件-end-event" aria-label="Permalink to &quot;2. 结束事件 (End Event)&quot;">​</a></h3><ul><li><strong>图标</strong>: 红色圆圈</li><li><strong>作用</strong>: 流程的终点，一个流程可以有多个结束事件</li><li><strong>属性</strong>: 无特殊配置</li><li><strong>规则</strong>: 只能有入边，不能有出边</li></ul><h3 id="_3-用户任务-user-task" tabindex="-1">3. 用户任务 (User Task) <a class="header-anchor" href="#_3-用户任务-user-task" aria-label="Permalink to &quot;3. 用户任务 (User Task)&quot;">​</a></h3><ul><li><strong>图标</strong>: 蓝色矩形（带人形标记）</li><li><strong>作用</strong>: 需要人工处理的任务节点</li><li><strong>属性</strong>: <ul><li><code>name</code> — 任务名称（必填）</li><li><code>candidate_users</code> — 候选用户 ID 列表</li><li><code>candidate_roles</code> — 候选角色名称列表</li><li><code>assignee</code> — 自动分配规则，支持 <code>\${variable}</code> 语法</li><li><code>due_duration</code> — 截止时间（ISO 8601 格式，如 <code>P1D</code> 表示 1 天）</li><li><code>form_key</code> — 关联的表单标识</li></ul></li></ul><h3 id="_4-审批任务-approval-task" tabindex="-1">4. 审批任务 (Approval Task) <a class="header-anchor" href="#_4-审批任务-approval-task" aria-label="Permalink to &quot;4. 审批任务 (Approval Task)&quot;">​</a></h3><ul><li><strong>图标</strong>: 橙色矩形（带勾选标记）</li><li><strong>作用</strong>: 需要审批决策的任务节点，审批结果会影响流程走向</li><li><strong>属性</strong>: <ul><li><code>name</code> — 审批名称（必填）</li><li><code>candidate_users</code> — 候选审批人列表</li><li><code>candidate_roles</code> — 候选审批角色</li><li><code>assignee</code> — 自动分配规则</li><li><code>due_duration</code> — 审批截止时间</li></ul></li><li><strong>特殊行为</strong>: 审批通过/驳回后会设置流程变量 <code>approved = true/false</code></li></ul><h3 id="_5-排他网关-exclusive-gateway" tabindex="-1">5. 排他网关 (Exclusive Gateway) <a class="header-anchor" href="#_5-排他网关-exclusive-gateway" aria-label="Permalink to &quot;5. 排他网关 (Exclusive Gateway)&quot;">​</a></h3><ul><li><strong>图标</strong>: 菱形（带 × 标记）</li><li><strong>作用</strong>: 条件分支，根据条件表达式选择唯一的执行路径</li><li><strong>属性</strong>: <ul><li><code>outgoing</code> — 出边列表</li><li><code>default_flow</code> — 默认流（当所有条件都不满足时走这条路径）</li></ul></li><li><strong>规则</strong>: 每条出边可以设置 <code>condition</code>，引擎按顺序评估，第一个满足条件的路径被选中</li></ul><h3 id="_6-并行网关-parallel-gateway" tabindex="-1">6. 并行网关 (Parallel Gateway) <a class="header-anchor" href="#_6-并行网关-parallel-gateway" aria-label="Permalink to &quot;6. 并行网关 (Parallel Gateway)&quot;">​</a></h3><ul><li><strong>图标</strong>: 菱形（带 + 标记）</li><li><strong>作用</strong>: 同时执行所有分支路径</li><li><strong>属性</strong>: 无特殊配置</li><li><strong>行为</strong>: 所有出边同时执行，所有入边都到达后才继续</li></ul><h2 id="操作指南" tabindex="-1">操作指南 <a class="header-anchor" href="#操作指南" aria-label="Permalink to &quot;操作指南&quot;">​</a></h2><h3 id="添加节点" tabindex="-1">添加节点 <a class="header-anchor" href="#添加节点" aria-label="Permalink to &quot;添加节点&quot;">​</a></h3><ol><li>从左侧面板拖拽节点类型到画布区域</li><li>节点会自动添加到画布中</li><li>点击节点在右侧属性面板中配置属性</li></ol><h3 id="连接节点" tabindex="-1">连接节点 <a class="header-anchor" href="#连接节点" aria-label="Permalink to &quot;连接节点&quot;">​</a></h3><ol><li>将鼠标悬停在节点上，出现连接点</li><li>从源节点的连接点拖拽到目标节点</li><li>松开鼠标完成连线</li><li>排他网关的出边需要在属性面板中设置条件</li></ol><h3 id="配置属性" tabindex="-1">配置属性 <a class="header-anchor" href="#配置属性" aria-label="Permalink to &quot;配置属性&quot;">​</a></h3><ol><li>点击画布中的节点或连线</li><li>右侧属性面板显示可编辑的属性</li><li>修改属性后自动保存到画布</li></ol><h3 id="删除元素" tabindex="-1">删除元素 <a class="header-anchor" href="#删除元素" aria-label="Permalink to &quot;删除元素&quot;">​</a></h3><ul><li>选中节点或连线后按 <code>Delete</code> 键</li><li>或右键选择&quot;删除&quot;</li></ul><h3 id="撤销-重做" tabindex="-1">撤销 / 重做 <a class="header-anchor" href="#撤销-重做" aria-label="Permalink to &quot;撤销 / 重做&quot;">​</a></h3><ul><li>快捷键 <code>Ctrl+Z</code>（撤销）/ <code>Ctrl+Shift+Z</code>（重做）</li><li>或点击工具栏中的撤销/重做按钮</li></ul><h2 id="保存流程" tabindex="-1">保存流程 <a class="header-anchor" href="#保存流程" aria-label="Permalink to &quot;保存流程&quot;">​</a></h2><ol><li>点击工具栏的&quot;保存&quot;按钮</li><li>首次保存需要填写： <ul><li>流程名称</li><li>流程标识（英文 key，创建后不可修改）</li><li>流程描述（可选）</li></ul></li><li>保存后会自动将画布内容转换为 BPMN JSON 存储到 <code>workflow_definitions.bpmn_definition</code></li></ol><h2 id="流程校验" tabindex="-1">流程校验 <a class="header-anchor" href="#流程校验" aria-label="Permalink to &quot;流程校验&quot;">​</a></h2><p>保存时引擎会自动校验：</p><ul><li>✅ 必须有开始事件</li><li>✅ 必须有结束事件</li><li>✅ 所有流的源和目标节点必须存在</li><li>✅ 网关必须有出边</li><li>✅ 非开始/结束节点不能是孤立节点（必须有入边和出边）</li></ul><p>校验失败时会显示错误信息，修复后才能保存。</p><h2 id="常用流程模式" tabindex="-1">常用流程模式 <a class="header-anchor" href="#常用流程模式" aria-label="Permalink to &quot;常用流程模式&quot;">​</a></h2><h3 id="简单审批流" tabindex="-1">简单审批流 <a class="header-anchor" href="#简单审批流" aria-label="Permalink to &quot;简单审批流&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开始 → 审批任务 → 排他网关</span></span>
<span class="line"><span>                    ├─ approved == true → 结束</span></span>
<span class="line"><span>                    └─ (默认) → 驳回通知 → 结束</span></span></code></pre></div><h3 id="串行多级审批" tabindex="-1">串行多级审批 <a class="header-anchor" href="#串行多级审批" aria-label="Permalink to &quot;串行多级审批&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开始 → 经理审批 → 排他网关</span></span>
<span class="line"><span>                  ├─ approved → 总监审批 → 排他网关</span></span>
<span class="line"><span>                  │                          ├─ approved → 结束</span></span>
<span class="line"><span>                  │                          └─ default → 退回经理</span></span>
<span class="line"><span>                  └─ default → 驳回通知 → 结束</span></span></code></pre></div><h3 id="并行会签" tabindex="-1">并行会签 <a class="header-anchor" href="#并行会签" aria-label="Permalink to &quot;并行会签&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开始 → 并行网关 → 审批人A → ┐</span></span>
<span class="line"><span>              → 审批人B → ├→ 并行网关（汇聚）→ 结束</span></span>
<span class="line"><span>              → 审批人C → ┘</span></span></code></pre></div><h2 id="快捷键" tabindex="-1">快捷键 <a class="header-anchor" href="#快捷键" aria-label="Permalink to &quot;快捷键&quot;">​</a></h2><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>Ctrl+S</code></td><td>保存</td></tr><tr><td><code>Ctrl+Z</code></td><td>撤销</td></tr><tr><td><code>Ctrl+Shift+Z</code></td><td>重做</td></tr><tr><td><code>Delete</code></td><td>删除选中元素</td></tr><tr><td><code>Ctrl+A</code></td><td>全选</td></tr><tr><td><code>Space + 拖拽</code></td><td>平移画布</td></tr><tr><td><code>滚轮</code></td><td>缩放画布</td></tr></tbody></table>`,46)])])}const g=e(i,[["render",t]]);export{u as __pageData,g as default};
